<script lang="ts">
  function newId() {
    return `_${Math.random().toString(36).slice(2)}`;
  }
</script>

<script setup lang="ts">
  const { id = newId() } = defineProps<{
    id?: string;
    label?: string;
    after?: boolean;
  }>();
</script>

<template>
  <label
    class="flex"
    :for="id"
  >
    <slot
      v-if="after"
      :id="id"
    ></slot>
    <span
      class="flex-grow select-none cursor-pointer uppercase text-current"
      :class="[!after && 'text-xs']"
    >
      <slot name="label">{{ label }}</slot>
    </span>
    <slot
      v-if="!after"
      :id="id"
    ></slot>
  </label>
</template>

<style lang="scss"></style>
